sql:
SELECT free_agent_type
   FROM free_agents
   WHERE free_agent_type = 'Restricted';

SELECT game_date, home_team_score
FROM schedules
ORDER BY game_date ASC;

external_knowledge:
- Injuries refer to instances where a player is unable to participate in a game due to health issues; 
- Transactions refer to events such as trades or signings that involve a player and affect their team status;
- Average points per game is a measure of a player's performance, calculated by dividing their total points by the number of games played.

sql:
SELECT team_id, AVG(points_scored_per_game) AS avg_points_scored
FROM team_seasons
GROUP BY team_id;

SELECT AVG(attendance) AS average_attendance
FROM schedules
WHERE season_id = 0;
